INSERT INTO tutoriels (titre, categorie, difficulte, duree, description, infos, etapes, lien) VALUES
(
  'Ameli - Assurance Maladie',
  'Santé',
  'débutant',
  '10 min',
  'Créez et gérez votre compte Ameli en ligne.',
  '["Votre numéro de sécurité sociale se trouve sur votre carte Vitale (15 chiffres)", "Le code d''activation est envoyé par courrier sous 48h ou par SMS si vous avez un numéro enregistré", "Une fois connecté, vous pouvez télécharger vos attestations et suivre vos remboursements", "Le compte Ameli est aussi accessible via l''application mobile sur smartphone"]',
  '[{"titre": "Aller sur ameli.fr", "description": "Ouvrez votre navigateur (Chrome, Firefox, Edge...) et tapez ameli.fr dans la barre d''adresse"}, {"titre": "Cliquer sur ''Créer mon compte''", "description": "Sur la page d''accueil, cliquez sur le bouton ''Mon compte'' en haut à droite, puis ''Créer mon compte''"}, {"titre": "Renseigner votre numéro de sécurité sociale", "description": "Saisissez vos 15 chiffres inscrits sur votre carte Vitale. Vérifiez bien chaque chiffre avant de valider"}, {"titre": "Valider votre identité", "description": "Vous recevrez un code d''activation par courrier (2 à 5 jours) ou par SMS. Entrez ce code sur le site pour activer votre compte"}, {"titre": "Créer votre mot de passe", "description": "Choisissez un mot de passe sécurisé d''au moins 8 caractères avec majuscule, chiffre et caractère spécial"}]',
  'https://www.ameli.fr'
),
(
  'CAF - Allocations Familiales',
  'Famille',
  'intermédiaire',
  '15 min',
  'Accédez à vos droits et gérez vos allocations familiales en ligne.',
  '["Votre numéro d''allocataire (7 chiffres) se trouve sur tout courrier reçu de la CAF", "Si vous n''avez pas encore de numéro, il faut d''abord faire une demande d''affiliation par courrier ou en agence", "Le code confidentiel vous est envoyé par courrier lors de votre première inscription", "Vous pouvez déclarer vos ressources, signaler un changement de situation et télécharger vos attestations depuis votre espace"]',
  '[{"titre": "Aller sur caf.fr", "description": "Ouvrez votre navigateur et tapez caf.fr dans la barre d''adresse"}, {"titre": "Accéder à ''Mon compte''", "description": "Cliquez sur ''Mon compte'' en haut à droite de la page d''accueil"}, {"titre": "Saisir vos identifiants", "description": "Entrez votre numéro d''allocataire (7 chiffres) et votre code confidentiel (6 chiffres) reçu par courrier"}, {"titre": "Consulter vos droits", "description": "Dans votre espace personnel, consultez vos allocations, vos paiements et téléchargez vos attestations de droits"}, {"titre": "Déclarer un changement", "description": "Si votre situation change (naissance, déménagement, revenus), signalez-le dans la rubrique ''Mes démarches'' pour ne pas perdre vos droits"}]',
  'https://www.caf.fr'
),
(
  'France Travail - Emploi',
  'Emploi',
  'intermédiaire',
  '20 min',
  'Inscrivez-vous et gérez votre espace France Travail (ex Pôle Emploi).',
  '["France Travail s''appelait Pôle Emploi jusqu''en 2024 — votre ancien compte reste valable", "Munissez-vous de votre pièce d''identité, de votre dernier contrat de travail et de votre attestation employeur", "Vous devez vous inscrire dans les 12 mois suivant la fin de votre contrat pour bénéficier des allocations", "L''actualisation mensuelle (entre le 28 et le 15 du mois suivant) est obligatoire pour continuer à toucher vos allocations"]',
  '[{"titre": "Aller sur francetravail.fr", "description": "Ouvrez votre navigateur et tapez francetravail.fr dans la barre d''adresse"}, {"titre": "Cliquer sur ''S''inscrire''", "description": "Sur la page d''accueil, cliquez sur le bouton ''S''inscrire comme demandeur d''emploi''"}, {"titre": "Remplir le formulaire", "description": "Renseignez votre état civil, votre adresse, votre dernier emploi et la raison de la fin de contrat. Ayez votre pièce d''identité sous la main"}, {"titre": "Compléter votre profil", "description": "Ajoutez votre CV, vos compétences, votre niveau d''études et votre secteur d''activité pour être visible des recruteurs"}, {"titre": "Suivre votre espace chaque mois", "description": "Actualisez votre situation chaque mois entre le 28 et le 15 pour continuer à recevoir vos droits. Consultez aussi vos offres d''emploi personnalisées"}]',
  'https://www.francetravail.fr'
);